"use client";
import { useRouter } from "next/navigation";
import { SiteForm } from "@/components/site/SiteForm";
import type { Site } from "@/lib/site-types";

const empty: Site = {
  id: "", name: "",
  crawl: { startUrls: [""], maxDepth: 2, maxPages: 50, allowSubdomains: false },
  visual: { enabled: true, maskSelectors: [], threshold: 0.1, maxDiffRatio: 0.01, viewport: { width: 1280, height: 800 } },
  dom: { enabled: true, ignoreSelectors: [], normalizeWhitespace: true },
  createdAt: "", updatedAt: "",
};

export default function NewSitePage() {
  const router = useRouter();
  async function handleSave(site: Site) {
    const res = await fetch("/api/sites", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(site),
    });
    const payload = await res.json();
    if (payload.success) router.push(`/sites/${site.id}/edit`);
    else alert(payload.error);
  }
  return (
    <main className="px-4 py-8">
      <h1 className="mb-4 text-2xl font-bold">새 사이트</h1>
      <SiteForm initial={empty} onSave={handleSave} />
    </main>
  );
}
```

