"use client";
import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { SiteForm } from "@/components/site/SiteForm";
import type { Site } from "@/lib/site-types";

export default function EditSitePage() {
  const params = useParams<{ id: string }>();
  const router = useRouter();
  const [site, setSite] = useState<Site | null>(null);

  useEffect(() => {
    void (async () => {
      const res = await fetch(`/api/sites/${params.id}`);
      const payload = await res.json();
      if (payload.success) setSite(payload.data);
    })();
  }, [params.id]);

  if (!site) return <main className="px-4 py-8">불러오는 중...</main>;

  return (
    <main className="px-4 py-8">
      <h1 className="mb-4 text-2xl font-bold">사이트 편집</h1>
      <SiteForm
        initial={site}
        onSave={async (next) => {
          await fetch(`/api/sites/${site.id}`, {
            method: "PUT",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(next),
          });
          router.push("/sites");
        }}
        storageStateUploader={async (json) => {
          await fetch(`/api/sites/${site.id}/storage-state`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(json),
          });
        }}
      />
    </main>
  );
}
